{
  "title": "Pengantar Python untuk Pendidik",
  "description": "Kursus ini dirancang untuk pendidik yang ingin memahami dasar-dasar pemrograman Python dan menerapkannya dalam konteks pengajaran. Kursus ini akan memberikan pemahaman yang kuat tentang sintaksis Python, struktur data, dan cara menggunakan Python untuk mendukung pembelajaran.",
  "modules": [
    {
      "id": "module_1",
      "title": "Pengenalan Python",
      "description": "Module ini memperkenalkan peserta pada Python, termasuk instalasi, lingkungan pengembangan, dan sintaks dasar. Peserta akan belajar cara menulis program sederhana dan memahami struktur dasar kode Python.",
      "facilitation_tips": "Gunakan papan tulis untuk menulis kode dan menjelaskan konsep. Ajak peserta untuk berpartisipasi dengan menulis kode secara langsung.",
      "activity": "Tulis program Python pertama yang mencetak 'Hello, World!'"
    },
    {
      "id": "module_2",
      "title": "Struktur Data dalam Python",
      "description": "Peserta akan mempelajari berbagai struktur data yang ada dalam Python, seperti list, tuple, dan dictionary. Module ini juga mencakup cara menggunakan struktur data ini dalam program.",
      "facilitation_tips": "Buat kelompok kecil untuk mendiskusikan penggunaan struktur data dalam konteks pengajaran.",
      "activity": "Buatlah program yang menggunakan list untuk menyimpan nama siswa dan mencetaknya."
    },
    {
      "id": "module_3",
      "title": "Kontrol Alur dan Fungsi",
      "description": "Module ini membahas kontrol alur menggunakan pernyataan kondisi dan loop. Peserta juga akan belajar cara mendefinisikan dan menggunakan fungsi dalam Python.",
      "facilitation_tips": "Ajak peserta untuk menyelesaikan masalah logika menggunakan kontrol alur. Diskusikan solusi secara kelompok.",
      "activity": "Buat fungsi yang menerima dua angka dan mengembalikan jumlahnya."
    },
    {
      "id": "module_4",
      "title": "Proyek Akhir: Aplikasi Python Sederhana",
      "description": "Peserta akan menerapkan semua yang telah dipelajari untuk membuat aplikasi Python sederhana. Ini dapat berupa kalkulator, permainan teks, atau aplikasi lain yang relevan untuk pendidikan.",
      "facilitation_tips": "Berikan waktu yang cukup untuk brainstorming dan pengembangan proyek. Dorong kolaborasi antar peserta.",
      "activity": "Rencanakan dan buat aplikasi Python sederhana yang dapat digunakan dalam konteks kelas."
    }
  ]
}
